issue_body:
**<u>AgentScope is an open-source project. To involve a broader community, we recommend asking your questions in English.</u>**

**Describe the bug**
When using the Qwen3-Max large language model, the same tool is invoked multiple times consecutively with identical parameters when multiple tools are available; switching to Qwen-Plus restores normal behavior.

**To Reproduce**
Steps to reproduce the behavior:

My Code
```
import asyncio
import random

from agentscope.agent import ReActAgent
from agentscope.formatter import DashScopeChatFormatter
from agentscope.memory import InMemoryMemory
from agentscope.message import Msg, TextBlock
from agentscope.model import DashScopeChatModel
from agentscope.tool import Toolkit, ToolResponse


async def calc_plus(
    num1: float,
    num2: float,
) -> ToolResponse:
    """
    加法计算器，计算两个数字的和

    Args:
        num1 (float): 第一个数字
        num2 (float): 第二个数字
    """

    return ToolResponse(
        content=[
            TextBlock(
                type="text",
                text=str(num1 + num2),
            ),
        ]
    )

async def calc_minus(
    num1: float,
    num2: float,
) -> ToolResponse:
    """
    减法计算器，计算两个数字的差

    Args:
        num1 (float): 第一个数字
        num2 (float): 第二个数字
    """

    return ToolResponse(
        content=[
            TextBlock(
                type="text",
                text=str(num1 - num2),
            ),
        ]
    )

async def get_weather(
    city: str,
) -> ToolResponse:
    """
    获取天气信息

    Args:
        city (str): 城市名称
    """
    weather_conditions = ["晴天", "多云", "雨天"]
    random_weather = random.choice(weather_conditions)
    location = city
    return ToolResponse(
        content=[
            TextBlock(
                type="text",
                text=f"{location}今天是{random_weather}。",
            ),
        ]
    )




async def creating_react_agent() -> None:
    """创建一个 ReAct 智能体并运行一个简单任务。"""
    # 准备工具
    toolkit = Toolkit()
    # 
    toolkit.register_tool_function(get_weather)
    toolkit.register_tool_function(calc_plus)
    toolkit.register_tool_function(calc_minus)

    jarvis = ReActAgent(
        name="Jarvis",
        sys_prompt="你是一个名为 Jarvis 的助手",
        model=DashScopeChatModel(
            model_name="qwen3-max",
            api_key="key",
            stream=True,
        ),
        formatter=DashScopeChatFormatter(),
        toolkit=toolkit,
        memory=InMemoryMemory(),
    )

    msg = Msg(
        name="user1",
        content="北京天气",
        role="user",
    )

    streaming = await jarvis(msg)

asyncio.run(creating_react_agent())
```

